pre.code:
import { Fetch } from 'metaowl'

Fetch.configure({
  baseUrl: 'https://api.example.com',
  headers: {
    'Authorization': 'Bearer token'
  }
})

// GET request
const users = await Fetch.get('/users')

// POST request
const newUser = await Fetch.post('/users', { name: 'John' })

// PUT request
await Fetch.put('/users/1', { name: 'Jane' })

// DELETE request
await Fetch.delete('/users/1')

const users = await Fetch.get('/users', {
  cache: { enabled: true, ttl: 60000 }
})
